1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const LOYALTY_DISCOUNT = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const FOLLOW_UP_CONTRACT_DISCOUNT = 0.15;
6	const FLOAT_ROUNDING_TOLERANCE = 1e-9;
7	const BLOCK_OF_THREE_DISCOUNT = 15;
8	
9	const BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const INSURANCE_VALUE: Record<string, number> = {
19	  sword: 1000,
20	  amulet: 600,
21	  staff: 800,
22	  potion: 400,
23	  rune: 250,
24	  moonstone: 250,
25	};
26	
27	const CAP_MULTIPLIER = 2;
28	
29	type Item = { type: string; cursed?: boolean; enchantment?: number };
30	type QuoteStep = { op: "quote"; items: Array<Item> };
31	type Damage = { itemType: string; amount: number };
32	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<Damage> } };
33	type Step = QuoteStep | ClaimStep;
34	type Customer = { yearsWithMHPCO: number };
35	type Scenario = {
36	  customer: Customer;
37	  steps: Array<Step>;
38	};
39	
40	const roundDownInMHPCOFavor = (amount: number): number =>
41	  Math.floor(amount + FLOAT_ROUNDING_TOLERANCE);
42	
43	const roundUpInMHPCOFavor = (amount: number): number =>
44	  Math.ceil(amount - FLOAT_ROUNDING_TOLERANCE);
45	
46	const requireDefined = <T>(value: T | undefined, errorMessage: string): T => {
47	  if (value === undefined) {
48	    throw new Error(errorMessage);
49	  }
50	  return value;
51	};
52	
53	const lookupByItemType = (table: Record<string, number>, item: Item): number =>
54	  requireDefined(table[item.type], `Unknown item type: ${item.type}`);
55	
56	const basePremiumOf = (item: Item): number => lookupByItemType(BASE_PREMIUM, item);
57	
58	const insuranceValueOf = (item: Item): number => lookupByItemType(INSURANCE_VALUE, item);
59	
60	const HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
61	
62	type ItemSurcharge = { applies: (item: Item) => boolean; rate: number };
63	
64	const ITEM_SURCHARGES: Array<ItemSurcharge> = [
65	  { applies: (item) => item.cursed === true, rate: 0.5 },
66	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD, rate: 0.3 },
67	];
68	
69	const surchargesFor = (item: Item): number =>
70	  ITEM_SURCHARGES.reduce(
71	    (sum, { applies, rate }) => sum + (applies(item) ? basePremiumOf(item) * rate : 0),
72	    0,
73	  );
74	
75	const sumOfBasePrices = (items: Array<Item>): number =>
76	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
77	
78	const sumOfItemSurcharges = (items: Array<Item>): number =>
79	  items.reduce((sum, item) => sum + surchargesFor(item), 0);
80	
81	const COMPONENT_TYPES = ["rune", "moonstone"];
82	const BLOCK_SIZE = 3;
83	
84	const countOfType = (items: Array<Item>, type: string): number =>
85	  items.filter((item) => item.type === type).length;
86	
87	const formsABlock = (items: Array<Item>, type: string): boolean =>
88	  countOfType(items, type) === BLOCK_SIZE;
89	
90	const blockDiscountFor = (items: Array<Item>): number =>
91	  COMPONENT_TYPES.filter((type) => formsABlock(items, type)).length *
92	  BLOCK_OF_THREE_DISCOUNT;
93	
94	const basePremiumFor = (items: Array<Item>): number =>
95	  sumOfBasePrices(items) - blockDiscountFor(items);
96	
97	type PolicyContext = { customer: Customer; isFollowUp: boolean };
98	type PolicyAdjustment = { applies: (ctx: PolicyContext) => boolean; signedRate: number };
99	
100	const POLICY_ADJUSTMENTS: Array<PolicyAdjustment> = [
101	  { applies: () => true, signedRate: +FIRST_INSURANCE_SURCHARGE },
102	  { applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, signedRate: -LOYALTY_DISCOUNT },
103	  { applies: ({ isFollowUp }) => isFollowUp, signedRate: -FOLLOW_UP_CONTRACT_DISCOUNT },
104	];
105	
106	const policyAdjustmentsOn = (policyBase: number, ctx: PolicyContext): number =>
107	  POLICY_ADJUSTMENTS.reduce(
108	    (sum, { applies, signedRate }) => sum + (applies(ctx) ? policyBase * signedRate : 0),
109	    0,
110	  );
111	
112	const quoteStep = (step: QuoteStep, ctx: PolicyContext): { premium: number } => {
113	  const policyBase = basePremiumFor(step.items);
114	  const premiumBeforeRounding =
115	    policyBase
116	    + policyAdjustmentsOn(policyBase, ctx)
117	    + sumOfItemSurcharges(step.items)
118	    + PROCESSING_FEE;
119	  return { premium: roundUpInMHPCOFavor(premiumBeforeRounding) };
120	};
121	
122	const DEDUCTIBLE = 100;
123	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
124	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
125	
126	const findInsuredItem = (policy: QuoteStep, itemType: string): Item =>
127	  requireDefined(
128	    policy.items.find((item) => item.type === itemType),
129	    `Item not in policy: ${itemType}`,
130	  );
131	
132	const reimbursementOf = (item: Item, damage: Damage): number =>
133	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
134	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
135	    : damage.amount;
136	
137	const payoutForDamage = (item: Item, damage: Damage): number =>
138	  reimbursementOf(item, damage) - DEDUCTIBLE;
139	
140	const sumOfInsuranceValues = (items: Array<Item>): number =>
141	  items.reduce((sum, item) => sum + insuranceValueOf(item), 0);
142	
143	const capFor = (policy: QuoteStep): number =>
144	  CAP_MULTIPLIER * sumOfInsuranceValues(policy.items);
145	
146	const countByType = (xs: Array<{ type?: string; itemType?: string }>, key: "type" | "itemType"): Map<string, number> => {
147	  const counts = new Map<string, number>();
148	  for (const x of xs) {
149	    const t = x[key] as string;
150	    counts.set(t, (counts.get(t) ?? 0) + 1);
151	  }
152	  return counts;
153	};
154	
155	const assertDamagesFitPolicy = (step: ClaimStep, policy: QuoteStep): void => {
156	  const insuredCounts = countByType(policy.items, "type");
157	  const damageCounts = countByType(step.incident.damages, "itemType");
158	  for (const [itemType, dmgCount] of damageCounts) {
159	    if (dmgCount > (insuredCounts.get(itemType) ?? 0)) {
160	      throw new Error(`Damage entries exceed insured count for: ${itemType}`);
161	    }
162	  }
163	};
164	
165	const claimStep = (
166	  step: ClaimStep,
167	  policy: QuoteStep,
168	  remainingCap: number,
169	): { payout: number; remainingCap: number } => {
170	  assertDamagesFitPolicy(step, policy);
171	  const payoutBeforeRounding = step.incident.damages.reduce(
172	    (sum, damage) => sum + payoutForDamage(findInsuredItem(policy, damage.itemType), damage),
173	    0,
174	  );
175	  const desiredPayout = roundDownInMHPCOFavor(payoutBeforeRounding);
176	  const payout = Math.min(desiredPayout, remainingCap);
177	  return { payout, remainingCap: remainingCap - payout };
178	};
179	
180	const isQuoteStep = (step: Step): step is QuoteStep => step.op === "quote";
181	
182	const claimAgainstRemainingCap = (
183	  step: ClaimStep,
184	  steps: Array<Step>,
185	  remainingCapByPolicy: Map<number, number>,
186	): { payout: number; remainingCap: number } => {
187	  const policy = steps[step.policy] as QuoteStep;
188	  const currentCap = remainingCapByPolicy.get(step.policy) ?? capFor(policy);
189	  const result = claimStep(step, policy, currentCap);
190	  remainingCapByPolicy.set(step.policy, result.remainingCap);
191	  return result;
192	};
193	
194	export const processScenario = (scenario: unknown): unknown => {
195	  const { customer, steps } = scenario as Scenario;
196	  const remainingCapByPolicy = new Map<number, number>();
197	  const results = steps.map((step, index) =>
198	    isQuoteStep(step)
199	      ? quoteStep(step, { customer, isFollowUp: index > 0 })
200	      : claimAgainstRemainingCap(step, steps, remainingCapByPolicy),
201	  );
202	  return { results };
203	};
